"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type Orientation = "horizontal" | "vertical"

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: Orientation
}

type StepperItemContextValue = {
  value: string
  index: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

// ─── Contexts ─────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

// ─── Hooks ────────────────────────────────────────────────────────────────────

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a Stepper.")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a StepperItem.")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

function Stepper({
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: Orientation
}) {
  const [_value, _setValue] = React.useState(defaultValue ?? "")
  const activeValue = value ?? _value

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (value === undefined) {
        _setValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [value, onValueChange]
  )

  const contextValue = React.useMemo<StepperContextValue>(
    () => ({
      value: activeValue,
      onValueChange: handleValueChange,
      orientation,
    }),
    [activeValue, handleValueChange, orientation]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("group/stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperList ──────────────────────────────────────────────────────────────

function StepperList({
  className,
  children,
  ...props
}: React.ComponentProps<"ol">) {
  const { value, orientation } = useStepper()

  const validChildren = React.Children.toArray(children).filter(
    React.isValidElement
  ) as React.ReactElement<{
    value: string
    completed?: boolean
    disabled?: boolean
  }>[]

  const stepValues = validChildren.map((child) => child.props.value)
  const activeIndex = stepValues.indexOf(value)

  return (
    <ol
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal" ? "flex-row items-start" : "flex-col",
        className
      )}
      {...props}
    >
      {validChildren.map((child, index) => {
        const itemValue = child.props.value
        const isActive = itemValue === value
        const isCompleted = child.props.completed ?? index < activeIndex
        const isDisabled = child.props.disabled ?? false

        return (
          <StepperItemContext.Provider
            key={itemValue}
            value={{ value: itemValue, index, isActive, isCompleted, isDisabled }}
          >
            {child}
          </StepperItemContext.Provider>
        )
      })}
    </ol>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

function StepperItem({
  value: _value,
  completed: _completed,
  disabled: _disabled,
  className,
  children,
  ...props
}: React.ComponentProps<"li"> & {
  value: string
  completed?: boolean
  disabled?: boolean
}) {
  const { isActive, isCompleted, isDisabled } = useStepperItem()
  const { orientation } = useStepper()

  return (
    <li
      data-slot="stepper-item"
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      data-disabled={isDisabled || undefined}
      data-orientation={orientation}
      className={cn(
        "group/stepper-item flex",
        orientation === "horizontal"
          ? "flex-1 flex-row items-center gap-2"
          : "flex-col",
        className
      )}
      {...props}
    >
      {children}
    </li>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isDisabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      disabled={isDisabled}
      onClick={() => onValueChange(value)}
      className={cn(
        "inline-flex items-center gap-2 rounded-sm text-left disabled:pointer-events-none disabled:opacity-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ─────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { index, isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "border-border bg-background text-muted-foreground",
        "data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? <CheckIcon className="size-4" /> : index + 1}
    </span>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-active={isActive || undefined}
      className={cn(
        "text-sm font-medium leading-none text-muted-foreground transition-colors data-[active]:text-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { isCompleted } = useStepperItem()
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      data-orientation={orientation}
      className={cn(
        "rounded-full bg-border transition-colors data-[completed]:bg-primary",
        orientation === "horizontal"
          ? "h-0.5 flex-1 min-w-6"
          : "ml-[15px] w-0.5 flex-1 min-h-5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ─────────────────────────────────────────────────────────────

function StepperPanel({
  value,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { value: activeValue } = useStepper()
  const isActive = value === activeValue

  return (
    <div
      data-slot="stepper-panel"
      data-active={isActive || undefined}
      hidden={!isActive}
      className={cn("", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}

