"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    value: "1",
    title: "Account",
    description: "Set up your account",
  },
  {
    value: "2",
    title: "Profile",
    description: "Complete your profile",
  },
  {
    value: "3",
    title: "Review",
    description: "Confirm your details",
  },
]

export default function StepperDemo() {
  const [step, setStep] = React.useState("1")

  const currentIndex = steps.findIndex((s) => s.value === step)

  function handleNext() {
    const next = steps[currentIndex + 1]
    if (next) setStep(next.value)
  }

  function handleBack() {
    const prev = steps[currentIndex - 1]
    if (prev) setStep(prev.value)
  }

  return (
    <Stepper value={step} onValueChange={setStep} className="w-full max-w-xl">
      <StepperList>
        {steps.map((s, index) => (
          <StepperItem key={s.value} value={s.value}>
            <StepperTrigger>
              <StepperIndicator />
              <div className="flex flex-col gap-0.5">
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </div>
            </StepperTrigger>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </StepperList>

      {steps.map((s) => (
        <StepperPanel key={s.value} value={s.value}>
          <div className="rounded-lg border p-6">
            <h3 className="mb-2 text-base font-semibold">{s.title}</h3>
            <p className="mb-6 text-sm text-muted-foreground">
              This is the content for the {s.title.toLowerCase()} step. Fill in
              the required information to proceed.
            </p>
            <div className="flex gap-2">
              {currentIndex > 0 && (
                <Button variant="outline" onClick={handleBack}>
                  Back
                </Button>
              )}
              {currentIndex < steps.length - 1 ? (
                <Button onClick={handleNext}>Next</Button>
              ) : (
                <Button onClick={() => setStep("1")}>Complete</Button>
              )}
            </div>
          </div>
        </StepperPanel>
      ))}
    </Stepper>
  )
}

