        "border-border bg-background text-muted-foreground",
        "data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? <CheckIcon className="size-4" /> : index + 1}
    </span>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-active={isActive || undefined}
      className={cn(
        "text-sm font-medium leading-none text-muted-foreground transition-colors data-[active]:text-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
