  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      data-orientation={orientation}
      className={cn(
        "rounded-full bg-border transition-colors data-[completed]:bg-primary",
        orientation === "horizontal"
          ? "h-0.5 flex-1 min-w-6"
          : "ml-[15px] w-0.5 flex-1 min-h-5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ─────────────────────────────────────────────────────────────

function StepperPanel({
  value,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { value: activeValue } = useStepper()
  const isActive = value === activeValue

  return (
    <div
      data-slot="stepper-panel"
      data-active={isActive || undefined}
      hidden={!isActive}
      className={cn("", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}

