"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/radix/components/example"
import { Button } from "@/registry/bases/radix/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/radix/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperBasic />
      <StepperVertical />
      <StepperWithDisabled />
    </ExampleWrapper>
  )
}

function StepperBasic() {
  const steps = [
    { value: "1", title: "Account", description: "Set up your account" },
    { value: "2", title: "Profile", description: "Complete your profile" },
    { value: "3", title: "Review", description: "Confirm your details" },
  ]

  const [step, setStep] = React.useState("1")
  const currentIndex = steps.findIndex((s) => s.value === step)

  return (
    <Example title="Basic">
      <Stepper
        value={step}
        onValueChange={setStep}
        className="w-full max-w-xl"
      >
        <StepperList>
          {steps.map((s, index) => (
            <StepperItem key={s.value} value={s.value}>
              <StepperTrigger>
                <StepperIndicator />
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        {steps.map((s) => (
          <StepperPanel key={s.value} value={s.value}>
            <div className="mt-2 rounded-lg border p-4">
              <p className="mb-4 text-sm text-muted-foreground">
                Content for the {s.title} step.
              </p>
              <div className="flex gap-2">
                {currentIndex > 0 && (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setStep(steps[currentIndex - 1].value)}
                  >
                    Back
                  </Button>
                )}
                {currentIndex < steps.length - 1 ? (
                  <Button
                    size="sm"
                    onClick={() => setStep(steps[currentIndex + 1].value)}
                  >
                    Next
                  </Button>
                ) : (
                  <Button size="sm" onClick={() => setStep("1")}>
                    Complete
                  </Button>
                )}
              </div>
            </div>
          </StepperPanel>
        ))}
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  const steps = [
    { value: "1", title: "Personal Info", description: "Your basic information" },
    { value: "2", title: "Contact", description: "How to reach you" },
    {
      value: "3",
      title: "Preferences",
      description: "Customize your experience",
    },
  ]

  const [step, setStep] = React.useState("2")

  return (
    <Example title="Vertical">
      <Stepper
        value={step}
        onValueChange={setStep}
        orientation="vertical"
        className="w-full max-w-xs"
      >
        <StepperList>
          {steps.map((s, index) => (
            <StepperItem key={s.value} value={s.value}>
              <StepperTrigger>
                <StepperIndicator />
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>
      </Stepper>
    </Example>
  )
}

function StepperWithDisabled() {
  const steps = [
    { value: "1", title: "Step 1", description: "Available", disabled: false },
    { value: "2", title: "Step 2", description: "Locked", disabled: true },
    { value: "3", title: "Step 3", description: "Available", disabled: false },
  ]

  return (
    <Example title="With Disabled">
      <Stepper defaultValue="1" className="w-full max-w-xl">
        <StepperList>
          {steps.map((s, index) => (
            <StepperItem key={s.value} value={s.value} disabled={s.disabled}>
              <StepperTrigger>
                <StepperIndicator />
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
              {index < steps.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>
      </Stepper>
    </Example>
  )
}

